class Solution:
    def getGoodIndices(self, variables, target):
        def modpow(base, exp, mod):
            if mod == 1:
                return 0
            result = 1
            base = base % mod
            e = exp
            while e > 0:
                if e & 1:
                    result = (result * base) % mod
                e >>= 1
                base = (base * base) % mod
            return result
        res = []
        for i in range(len(variables)):
            a, b, c, m = variables[i]
            x = modpow(a, b, 10)
            y = modpow(x, c, m)
            if y == target:
                res.append(i)
        return res

