var getGoodIndices = function(variables, target) {
    function modpow(base, exp, mod) {
        if (mod === 1) return 0;
        let result = 1;
        base = base % mod;
        let e = exp;
        while (e > 0) {
            if (e & 1) {
                result = (result * base) % mod;
            }
            e = Math.floor(e / 2);
            base = (base * base) % mod;
        }
        return result;
    }
    const res = [];
    for (let i = 0; i < variables.length; i++) {
        const [a, b, c, m] = variables[i];
        const x = modpow(a, b, 10);
        const y = modpow(x, c, m);
        if (y === target) res.push(i);
    }
    return res;
};
